data class IoTDevice(
    val id: String,
    val name: String,
    val ipAddress: String,
    val port: Int = 80
) {
    fun getBaseUrl(): String = "http://$ipAddress:$port"
}

class IoTDeviceManager(private val httpClient: IoTHttpClient) {

    suspend fun getDeviceStatus(device: IoTDevice): String? {
        return try {
            val response = httpClient.get("${device.getBaseUrl()}/status")
            if (response.isSuccessful) {
                response.body?.string()
            } else {
                null
            }
        } catch (e: Exception) {
            null
        }
    }

    suspend fun sendCommand(device: IoTDevice, command: String, payload: String): Boolean {
        return try {
            val response = httpClient.post(
                "${device.getBaseUrl()}/command/$command",
                payload
            )
            response.isSuccessful
        } catch (e: Exception) {
            false
        }
    }

    suspend fun updateDeviceConfig(device: IoTDevice, config: String): Boolean {
        return try {
            val response = httpClient.put(
                "${device.getBaseUrl()}/config",
                config
            )
            response.isSuccessful
        } catch (e: Exception) {
            false
        }
    }
}

